def validate_numeric_field(name: str, value: float) -> float:
    args = [name, value]# type: ignore
    kwargs = {}# type: ignore
    return _mutmut_trampoline(x_validate_numeric_field__mutmut_orig, x_validate_numeric_field__mutmut_mutants, args, kwargs, None)


